var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"감사합니다. 멈추지 않는 인형들 때문에 골치였는데, 덕분에 살았어요.","JPN":"ありがとうございます。止まらない人形のせいで苦戦していたのですが、おかげで助かりました。","ENG":"Thank you. Those dolls that wouldn't stop moving were becoming a real problem. You saved us.","TWN":"謝謝你們。那些動不停的人偶真的很麻煩，多虧你們幫忙。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"천만에. 다른 함선 쪽을 돕느라 자네들과의 합류에 늦은 게 미안할 따름이군.","JPN":"いや。他の艦船を助けていて合流が遅くなった。すまない。","ENG":"Think nothing of it. I only regret that we were late to join you while helping the other ships.","TWN":"不客氣。反倒是我們忙著支援其他艦船來晚了，真抱歉。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데, 총사대장 귀하의 심장에 박힌 그 보물이 녀석들에게 효과가 있다는 건 어떻게 아셨죠?","JPN":"ところで、銃士隊長の心臓に刺さっているその宝物がやつらに効くと、どうして分かったんですか？","ENG":"But how did you know that the thing embedded in your heart would be effective against them, General Musketeer?","TWN":"不過你們是怎麼知道，那個嵌在你心臟的寶物對那些傢伙有效？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"몸소 우릴 찾아주신 주정뱅이 요정님에게 노르드나빅 최고의 감자술을 대접하고 조언을 받았거든.","JPN":"自ら我々を訪ねてくださった酔っ払いの妖精様に、ノルドナビック最高のジャガイモ酒でもてなし、助言をいただいたんだ。","ENG":"A certain drunken fairy who came to see us in person offered some advice after we treated her to Nordnavik's finest spud ale.","TWN":"我請了一個找上門的酒鬼精靈喝諾爾德萊比最好的馬鈴薯酒，然後從他那裡得到了建議。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"요정?","JPN":"妖精？","ENG":"A fairy?","TWN":"精靈？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그런 게 진짜로 있는 건가요?","JPN":"妖精って本当にいるんですか？","ENG":"Do those really exist?","TWN":"那種東西真的存在嗎？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"어디까지나 당사자의 주장일 뿐입니다만- 정황상 발언에 꽤 신빙성이 있다고 판단했습니다.","JPN":"あくまで本人がそう主張しているだけですが……状況的に発言内容の信憑性はかなり高いと判断しました。","ENG":"That's only what the person in question claims. But given the circumstances, we judged the statement to be quite credible.","TWN":"雖然只是對方的說法—但從各種跡象來看，我判斷他的發言相當可信。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"역사가들조차 모르는 저희 노르드나빅의 기원사와 앞으로 일어나게 될 일에 대한 예언을 했는데, 전부 경이로울 정도로 맞아 떨어지더군요.","JPN":"歴史研究者ですら知らない我々ノルドナビックの起源史や、これから起こることについて予言をしたのですが、すべて驚くほど当てはまったんです。","ENG":"She spoke of Nordnavik's origin history, things even historians don't know, and made predictions about what was yet to come. Every single one proved astonishingly accurate.","TWN":"他甚至預言了連歷史學家都不知道的諾爾德萊比起源，以及未來會發生的事，而且幾乎全都準確無誤。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"예언이라면, 그자는 이곳에 어떤 일이 벌어질지도 알고 있었단 건가?","JPN":"予言なら、その者はここで何が起こるかも分かっていたということか？","ENG":"If it was a prophecy, does that mean they even knew what would happen here?","TWN":"既然是預言，那他也知道這裡會發生什麼囉？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리 명료한 메시지는 아니었습니다. 여러 방면으로 해석이 가능한 뭉뚱그려진 이야기였죠.","JPN":"そこまではっきりとしたメッセージではありません。色んな意味に解釈できる、大雑把な話でした。","ENG":"It wasn't such a clear message. It was rather vague and open to interpretation in several ways.","TWN":"倒也不是那麼明確的訊息，只是一些可以從各種角度解讀的模糊內容。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그 중엔 당신에 관한 이야기도 있었습니다.","JPN":"中にはあなたに関する話もありました。","ENG":"Among it... there was also something about you.","TWN":"其中也提到了你。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"...니콜 프라이머.","JPN":"……ニコル・プライマー。","ENG":"...Nicole Primer.","TWN":"……妮可．布萊伊莫小姐。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"콜록-","JPN":"ゲホッ。","ENG":"*Cough*","TWN":"咳咳－"},"stage":{"bg":"PATH","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"콜록, 콜록... 콜록...","JPN":"ゲ、ゲホッ、ゲホッ……","ENG":"*Cough* *Cough...* *Cough...*","TWN":"咳咳、咳咳……咳咳……"},"stage":{"bg":"PATH","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"콜록... 죄, 죄송... 콜록...","JPN":"ゲホッ……す、すみま……ゲホッ……","ENG":"*Cough...* S-sorry... *Cough...*","TWN":"咳咳……"},"stage":{"bg":"PATH","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그러게 뭔가를 마시고 있을 때 이름을 부르면 안 된다니까.","JPN":"だから、何かを飲んでいる時に名前を呼んではいけないと言ったじゃないか。","ENG":"That's why I said not to call someone's name while they're drinking something.","TWN":"就說不要在人家喝東西的時候突然叫我名字。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"크, 크음... 저 말씀이신가요?","JPN":"ご、ごほん……私ですか？","ENG":"Ahem... Y-you mean me?","TWN":"咳、咳……你是說我嗎？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래. 요정께선 자네가 노르드나빅을 구원할 전승 속 성녀 마르가리타의 현신이라고 하더군.","JPN":"ああ。妖精様は君のことをノルドナビックを救う者、伝承の中の聖女マルガリータの現身と言っていた。","ENG":"Yes. The fairy said you are the incarnation of Saintess Margarita from the legends who will save Nordnavik.","TWN":"沒錯。那位精靈說，你是拯救諾爾德萊比的傳說聖女瑪格麗特的化身。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"콜록-","JPN":"ゲホッ。","ENG":"*Cough*","TWN":"咳咳－"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"...성녀요? 제가요? 그럴 리가 없지요?","JPN":"……聖女？　私がですか？　そんなわけありませんよ？","ENG":"...A Saintess? Me? That can't be right.","TWN":"……聖女？我？怎麼可能？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"본인의 정체가 의심된다면 지금 바로 교차 검증을 해보죠.","JPN":"本人の正体が疑わしいなら、今すぐクロスチェックをしてみましょう。","ENG":"If you doubt your own identity, we can conduct a cross-check right now.","TWN":"如果你懷疑自己的身分，那就現場做個交叉驗證吧。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"여러분 중에 이 아가씨가 쏜 총알이 빗나가는 걸 목격한 사람이 있습니까?","JPN":"皆さんの中で、このお嬢さんが撃った弾が外れたところを目撃した人はいますか？","ENG":"Has anyone here witnessed this young lady's bullets missing their target?","TWN":"各位有人看過這位小姐射出的子彈失手嗎？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...적어도 백 발 정도는 쏘셨던 것 같은데-","JPN":"……少なくとも100発は撃っていたと思いますが……","ENG":"...She's fired at least around a hundred shots, I think...","TWN":"……她至少開了上百槍吧—"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"...되살아난 녀석은 있어도, 딱히 빗맞힌 적은 없지 않아?","JPN":"……敵が蘇ったことはあっても、外したことはなかったんじゃない？","ENG":"...Some of them got back up afterward, but I don't recall any of them actually missing, do you?","TWN":"……雖然有復活的，但好像沒看過她打偏耶？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"한 번도 못 봤는데요?","JPN":"一度も見ませんでしたよ。","ENG":"I've never seen one miss.","TWN":"一次都沒有耶？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이걸로 검증 완료군요.","JPN":"これでチェック完了ですね。","ENG":"That settles the verification.","TWN":"這樣就驗證完成了。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"잠깐만요. 그렇게 간단히?","JPN":"待ってください。こんなに簡単に？","ENG":"Wait a moment. Just like that?","TWN":"等一下，就這麼簡單？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"상황이 상황인만큼 검증은 약식으로 진행할 수 밖에 없는 점 양해 바랍니다.","JPN":"こんな状況ですので、チェックは略式で行うしかないことをご理解ください。","ENG":"Given the situation, please understand that the verification had to be conducted in a simplified manner.","TWN":"情況緊急，只能簡化流程，還請見諒。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"굳이 제 사견을 보태자면, 필중의 마탄을 가졌단 사실 하나만으로 이미 정상 범주를 아득히 초월한 기인이라고 생각합니다만.","JPN":"私見を添えますと、必中の魔弾を持っているという事実だけでも、すでに正常の範疇を遥かに超えた超人だと思いますが。","ENG":"If I may add my personal opinion, the fact that you possess unfailing demon bullets alone already places you far beyond the bounds of normal people.","TWN":"以我個人的看法，光是擁有必中魔彈這一點，就已經遠遠超出常人的範疇了。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"부정할 수 없군요.","JPN":"否定できませんね。","ENG":"I can't deny that.","TWN":"這點我無法否認。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"신기하네요. 쏘는 거라면 저도 자주 빗나가는데.","JPN":"不思議ですね。射撃なら私もよく外すのに。","ENG":"That's amazing. I miss my shots all the time when I shoot things.","TWN":"真神奇。我自己射擊的時候，常常都會打偏。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};